import { mkdir, copyFile } from 'node:fs/promises';
import { resolve, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

const rootDir = resolve(__dirname, '..');
const srcDir = resolve(rootDir, 'src');
const outDir = resolve(rootDir, 'wwwroot', 'dist');

async function main() {
  // Ensure output directories exist
  await mkdir(outDir, { recursive: true });

  // --- App stylesheet: src/app.css -> wwwroot/dist/app.css ---
  const srcPath = resolve(srcDir, 'app.css');
  const destPath = resolve(outDir, 'app.css');
  try {
    await copyFile(srcPath, destPath);
  } catch {
    // If src/app.css doesn't exist, skip silently.
  }

  // --- Bootstrap Icons (icon pack) ---
  // Vendored as-is so the CSS's relative `./fonts/...` references resolve.
  // Layout under dist/icons:
  //   bootstrap-icons.css
  //   fonts/bootstrap-icons.woff2
  //   fonts/bootstrap-icons.woff
  const biPkgDir = resolve(rootDir, 'node_modules', 'bootstrap-icons', 'font');
  const iconsDir = resolve(outDir, 'icons');
  const iconsFontsDir = resolve(iconsDir, 'fonts');
  await mkdir(iconsFontsDir, { recursive: true });

  const biAssets = [
    ['bootstrap-icons.css', 'bootstrap-icons.css'],
    ['fonts/bootstrap-icons.woff2', 'fonts/bootstrap-icons.woff2'],
    ['fonts/bootstrap-icons.woff', 'fonts/bootstrap-icons.woff'],
  ];
  for (const [from, to] of biAssets) {
    await copyFile(resolve(biPkgDir, from), resolve(iconsDir, to));
  }
}

main();

/**
 * ESLint flat config.
 *
 * NOTE: this project's primary linter is `oxlint` (see `.oxlintrc.json` and
 * `npm run lint`). ESLint is not a project dependency; this config exists so
 * that environments which invoke ESLint (e.g. `npx eslint .`) have a valid
 * configuration to load instead of erroring with "couldn't find an
 * eslint.config file".
 *
 * TypeScript sources are linted by oxlint. ESLint cannot parse TypeScript
 * syntax without the `typescript-eslint` parser (not installed here), so a
 * lenient passthrough parser is used for `.ts`/`.tsx` files: the file is
 * "matched" (avoiding the noisy "file ignored" warning) but produces an empty
 * AST, and with no rules configured no violations are reported. Real linting
 * remains the responsibility of oxlint.
 */
const lenientParser = {
  parseForESLint() {
    return {
      ast: {
        type: 'Program',
        body: [],
        sourceType: 'module',
        comments: [],
        tokens: [],
        range: [0, 0],
        loc: { start: { line: 1, column: 0 }, end: { line: 1, column: 0 } },
      },
      visitorKeys: {},
      scopeManager: null,
      services: {},
    };
  },
};

export default [
  {
    ignores: [
      'node_modules/',
      '.engin/',
      'wwwroot/',
      'bin/',
      'obj/',
      'dist/',
      'SampleFiles/',
      'coverage/',
    ],
  },
  {
    files: ['**/*.{js,mjs,cjs,ts,mts,cts,jsx,tsx}'],
    languageOptions: {
      parser: lenientParser,
      ecmaVersion: 2022,
      sourceType: 'module',
    },
    rules: {},
  },
];

{
  "$schema": "https://raw.githubusercontent.com/oxc-project/oxc/main/npm/oxlint/configuration_schema.json",
  "ignorePatterns": [
    "node_modules/",
    ".engin/",
    "wwwroot/",
    "bin/",
    "obj/",
    "dist/",
    "SampleFiles/",
    "coverage/",
    "package-lock.json"
  ],
  "categories": {
    "correctness": "error"
  },
  "rules": {
    "no-console": "off"
  }
}

{
  "name": "filebrowser-ui",
  "private": true,
  "version": "1.0.0",
  "type": "module",
  "engines": {
    "node": ">=20"
  },
  "scripts": {
    "build": "tsc && node scripts/copy-assets.mjs",
    "watch": "tsc --watch",
    "test": "vitest run",
    "test:backend": "dotnet test TestProject.sln",
    "lint": "oxlint .",
    "lint:fix": "oxlint --fix .",
    "format": "prettier --write .",
    "format:check": "prettier --check .",
    "prepare": "simple-git-hooks"
  },
  "dependencies": {
    "bootstrap-icons": "^1.13.1"
  },
  "devDependencies": {
    "happy-dom": "^15.7.4",
    "lint-staged": "^16.4.0",
    "oxlint": "^1.70.0",
    "prettier": "^3.8.4",
    "simple-git-hooks": "^2.13.1",
    "typescript": "^5.6.3",
    "vitest": "^2.1.4"
  },
  "simple-git-hooks": {
    "pre-commit": "npx lint-staged"
  },
  "lint-staged": {
    "*.{ts,mts,cts,mjs,cjs,js,jsx,tsx,json,jsonc,css,scss,md,yml,yaml}": "prettier --write",
    "*.{ts,mts,cts,mjs,cjs,js,jsx,tsx}": "oxlint --fix",
    "*.cs": "dotnet format TestProject.sln --include"
  }
}

import { defineConfig } from 'vitest/config';

export default defineConfig({
  test: {
    environment: 'happy-dom',
    include: ['src/**/*.test.ts'],
  },
});

{
  "Logging": {
    "LogLevel": {
      "Default": "Information",
      "Microsoft.AspNetCore": "Warning"
    }
  },
  "AllowedHosts": "*",
  "FileService": {
    "HomeDirectory": "SampleFiles"
  }
}

